const results = $.steps.webResearch.response.results || [];
let sourcesText = '';
results.forEach((r, i) => {
  sourcesText += (i+1) + '. ' + (r.title || 'Untitled') + '\n';
  sourcesText += '   URL: ' + r.url + '\n';
  if (r.publishedDate) sourcesText += '   Published: ' + r.publishedDate + '\n';
  sourcesText += '   ' + (r.text || '').slice(0, 1200) + '\n\n';
});
return { sourcesText, sourceCount: results.length, topSources: results.slice(0, 5).map(r => ({ title: r.title || 'Untitled', url: r.url })) };

const depth = $.input.depth || 'standard';
const prompt = `You are an expert research analyst. Conduct a ${depth}-depth analysis on the following topic using the provided sources.

RESEARCH TOPIC: ${$.input.topic}

SOURCES (${$.steps.compileSources.output.sourceCount} found):
${$.steps.compileSources.output.sourcesText}

INSTRUCTIONS:
- Provide a comprehensive research summary
- Identify key findings, trends, and insights
- Note any conflicting information between sources
- Cite sources by number [1], [2], etc.
- Include actionable takeaways
- Use Slack mrkdwn formatting: *bold*, _italic_, numbered lists
- Slack rules: use *bold* (NOT **bold**). No markdown tables. No # headings.

Return ONLY valid JSON:
{
  "summary": "<research summary in Slack mrkdwn>",
  "keyFindings": ["<finding1>", "<finding2>"],
  "trends": ["<trend1>", "<trend2>"],
  "takeaways": ["<actionable takeaway1>", "<takeaway2>"],
  "confidence": "high|medium|low",
  "gapsIdentified": ["<what needs more research>"]
}`;
return { prompt };

let raw = $.steps.aiAnalysis.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { summary: raw, keyFindings: [], trends: [], takeaways: [], confidence: 'medium', gapsIdentified: [] }; }

const ai = $.steps.parseAI.output || {};
const topic = $.input.topic;
const confidenceEmoji = ai.confidence === 'high' ? ':large_green_circle:' : ai.confidence === 'low' ? ':red_circle:' : ':large_yellow_circle:';

const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: 'Research Report' } });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Topic:* ' + topic } });
blocks.push({ type: 'divider' });

const summaryText = (ai.summary || 'No summary generated.').slice(0, 1900);
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: summaryText } });
blocks.push({ type: 'divider' });

if (ai.keyFindings && ai.keyFindings.length > 0) {
  let kfText = '*Key Findings:*\n';
  ai.keyFindings.forEach((f, i) => { kfText += (i+1) + '. ' + f + '\n'; });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: kfText.slice(0, 1900) } });
  blocks.push({ type: 'divider' });
}

if (ai.takeaways && ai.takeaways.length > 0) {
  let taText = '*Actionable Takeaways:*\n';
  ai.takeaways.forEach((t, i) => { taText += (i+1) + '. ' + t + '\n'; });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: taText.slice(0, 1900) } });
}

blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: confidenceEmoji + ' Confidence: *' + (ai.confidence || 'medium') + '* | Sources: *' + $.steps.compileSources.output.sourceCount + '* | Depth: *' + ($.input.depth || 'standard') + '*' }] });

const fallback = 'Research report on: ' + topic;
return { blocks, fallback };
